var score = 0;
var health = 20;
var gameState = "play";
var player = createSprite(200, 350);
player.setAnimation("blue_shirt_hand_up_1");
player.scale = 0.5;
var coin = createSprite(200, 200);
coin.setAnimation("coin_gold_1");
coin.scale = 0.3;
var enemy = createSprite(randomNumber(50, 350), 0);
enemy.setAnimation("kid_42_1");
enemy.scale = 0.5;
enemy.velocityY = 2;
function draw() {
  if (gameState === "play") {
   if (score < 30) {
     background("lightblue"); 
   } else if (score < 60) {
     background("lightgreen"); 
   } else {
     background("lightyellow"); 
   }
   handlePlayerInput();
   moveEnemyComplex();
   checkCollisions();
   drawSprites();
   fill("white");
   textSize(20);
   text("Arrows and mouse to move", 100, 200);
   drawHUD(); 
   if (score >= 100) {
     gameState = "win";
   }
   if (health <= 0) {
     gameState = "lose";
   }
  } else if (gameState === "lose") {
   background("red");
   fill("white");
   textSize(40);
   text("Game Over", 100, 200);
   text("Score: " + score, 110, 250);
  } else if (gameState === "win") {
   background("yellow");
   fill("black");
   textSize(40);
   text("You Win!", 120, 200);
  }
}
function handlePlayerInput() {
  if (keyDown("up")) {
    player.y = player.y - 3;
  }
  if (keyDown("down")) {
    player.y = player.y + 3;
  }
  if (keyDown("left")) {
    player.x = player.x - 3;
  }
  if (keyDown("right")) {
    player.x = player.x + 3;
  }
  if (World.mouseX > 0) {
    player.x = World.mouseX;
    player.y = World.mouseY;
  }
}
function moveEnemyComplex() {
  if (enemy.y > 400) {
    enemy.y = 0;
    enemy.x = randomNumber(50, 350);
  }
}
function checkCollisions() {
  if (player.isTouching(coin)) {
    score = score + 10;
    coin.x = randomNumber(50, 350);
    coin.y = randomNumber(50, 300);
  }
  if (player.isTouching(enemy)) {
    health = health - 5;
    enemy.y = 0; 
    enemy.x = randomNumber(50, 350);
  }
}
function drawHUD() {
  fill("black");
  textSize(20);
  text("Coins: " + score, 10, 30);
  text("Health: " + health, 10, 60);
}
